Javascript.miscCode:
OracleReportForm.refDataServices = [
	{name:"WarrantReturnCodes", dataBinding:REF_DATA_XPATH, serviceName:"getWarrantReturnCodes", serviceParams:[{ name: "courtCode", value: "/ds/var/app/currentCourt", type: "simple" }]},
	{name:"Courts", dataBinding:REF_DATA_XPATH, serviceName:"getCourtsShort", serviceParams:[]},
	{name:"SystemDate", dataBinding:REF_DATA_XPATH, serviceName:"getSystemDate", serviceParams:[]}
];		

function validateReturnCode()
{
	var enteredValue = Services.getValue(ReturnCode.dataBinding);
	if (enteredValue == "%")
	{
		return null;
	}
	var found = false;
	var ec = null;
	var numberOfWarrantReturnCodes = Services.getNodes(REF_DATA_XPATH + "/ds/WarrantReturnCodes/WarrantReturnCode").length;
	for(var i=1; i <= numberOfWarrantReturnCodes; i++)
	{
		var code = Services.getValue(REF_DATA_XPATH + "/ds/WarrantReturnCodes/WarrantReturnCode[" + i + "]/Code");
		if (code == enteredValue)
		{
			found = true;
			break;
		}
	}
	if (!found)
	{
		Services.setFocus("ReturnCode");
		ec = ErrorCode.getErrorCode("CaseMan_invalidWarrantCode_Msg");
		faildedValidation (ec);
	}
	return ec;
}
